option.value:
plugins {
    id 'java'
    id 'org.jetbrains.kotlin.jvm' version '2.1.10'
    id 'org.jetbrains.intellij.platform' version '2.5.0'
}

group = 'dev.veld'
version = '0.6.0'

repositories {
    mavenCentral()
    intellijPlatform {
        defaultRepositories()
    }
}

dependencies {
    intellijPlatform {
        // Build against 2025.1 (build 251). Plugin runs on 251+ per since-build.
        intellijIdeaCommunity('2025.1')

        // JSON plugin provides com.jetbrains.jsonSchema.* for VeldConfigSchemaProviderFactory.
        bundledPlugin('com.intellij.modules.json')

        // Required for bytecode instrumentation.
        instrumentationTools()

        // Verify against the same platform we build against.
        pluginVerifier()
    }
    implementation "org.jetbrains.kotlin:kotlin-stdlib"
}

intellijPlatform {
    pluginConfiguration {
        ideaVersion {
            // 251 = IntelliJ 2025.1 (earliest version that requires Java 21 SDK).
            // Plugin is tested up to 263.* (2026.3).
            sinceBuild = '251'
            untilBuild = '263.*'
        }
    }

    pluginVerification {
        ides {
            recommended()
        }
    }

    signing {
        certificateChain = providers.environmentVariable("CERTIFICATE_CHAIN")
        privateKey = providers.environmentVariable("PRIVATE_KEY")
        password = providers.environmentVariable("PRIVATE_KEY_PASSWORD")
    }

    publishing {
        token = providers.environmentVariable("JETBRAINS_PUBLISH_TOKEN")
    }
}

// IntelliJ Platform 2025.1+ requires Java 21.
tasks.withType(JavaCompile).configureEach {
    sourceCompatibility = '21'
    targetCompatibility = '21'
}

tasks.withType(org.jetbrains.kotlin.gradle.tasks.KotlinCompile).configureEach {
    kotlinOptions {
        jvmTarget = '21'
    }
}

