{
  "name": "@maayn/veld",
  "version": "0.1.0",
  "description": "Contract-first, multi-stack API code generator. Write .veld contracts once, generate typed frontend SDKs and backend service interfaces.",
  "keywords": [
    "veld",
    "api",
    "code-generation",
    "contract-first",
    "typescript",
    "sdk",
    "schema"
  ],
  "homepage": "https://github.com/Adhamzineldin/Veld",
  "bugs": {
    "url": "https://github.com/Adhamzineldin/Veld/issues"
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/Adhamzineldin/Veld.git"
  },
  "license": "MIT",
  "bin": {
    "veld": "./bin/veld.js"
  },
  "engines": {
    "node": ">=16"
  },
  "files": [
    "bin/",
    "binaries/",
    "README.md",
    "LICENSE"
  ]
}

{
  "name": "@maayn/veld",
  "version": "0.1.0",
  "description": "Contract-first, multi-stack API code generator. Write .veld contracts once, generate typed frontend SDKs and backend service interfaces.",
  "keywords": [
    "veld",
    "api",
    "code-generation",
    "contract-first",
    "typescript",
    "sdk",
    "schema"
  ],
  "homepage": "https://github.com/Adhamzineldin/Veld",
  "bugs": {
    "url": "https://github.com/Adhamzineldin/Veld/issues"
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/Adhamzineldin/Veld.git"
  },
  "license": "MIT",
